import{_ as a,o,c as l,a2 as t}from"./chunks/framework.BZO4qERu.js";const _=JSON.parse('{"title":"Leaflet GeoJSON 点线面渲染","description":"","frontmatter":{},"headers":[],"relativePath":"leaflet/geojson.md","filePath":"leaflet/geojson.md"}'),i={name:"leaflet/geojson.md"};function r(n,e,d,c,s,h){return o(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="leaflet-geojson-点线面渲染" tabindex="-1">Leaflet GeoJSON 点线面渲染 <a class="header-anchor" href="#leaflet-geojson-点线面渲染" aria-label="Permalink to &quot;Leaflet GeoJSON 点线面渲染&quot;">​</a></h1><p><a class="demo-link" href="/leaflet/geo-json-render" target="_blank">打开主应用 Demo：/leaflet/geo-json-render</a></p><h2 id="功能简介" tabindex="-1">功能简介 <a class="header-anchor" href="#功能简介" aria-label="Permalink to &quot;功能简介&quot;">​</a></h2><p>GeoJSON 是 WebGIS 中最常见的数据格式之一，适合表达点、线、面等轻量空间数据。</p><p>在 Leaflet 中，可以用 <code>L.geoJSON</code> 快速完成渲染，并通过 <code>style</code>、<code>pointToLayer</code>、<code>onEachFeature</code> 控制样式和交互。</p><h2 id="常见用途" tabindex="-1">常见用途 <a class="header-anchor" href="#常见用途" aria-label="Permalink to &quot;常见用途&quot;">​</a></h2><ul><li>点：站点、设备、告警位置。</li><li>线：道路、轨迹、管线、步行路线。</li><li>面：行政区、业务范围、覆盖区域。</li></ul><h2 id="实现思路" tabindex="-1">实现思路 <a class="header-anchor" href="#实现思路" aria-label="Permalink to &quot;实现思路&quot;">​</a></h2><ol><li>准备 <code>FeatureCollection</code> 数据。</li><li>根据 <code>properties.kind</code> 做分类样式。</li><li>点数据用 <code>circleMarker</code> 增强视觉控制。</li><li>点击要素时显示名称、类型和描述。</li></ol><h2 id="扩展方向" tabindex="-1">扩展方向 <a class="header-anchor" href="#扩展方向" aria-label="Permalink to &quot;扩展方向&quot;">​</a></h2><ul><li>接入接口返回的 GeoJSON。</li><li>支持图层开关。</li><li>支持按属性过滤。</li><li>支持自动缩放到 GeoJSON 范围。</li></ul>',11)])])}const u=a(i,[["render",r]]);export{_ as __pageData,u as default};
